// Agrupa todos os itens recebidos e calcula m�tricas de vendas
const items = $input.all();

let totalVendas = 0;
let totalPedidos = 0;
let melhorVendedor = { nome: '', valor: 0 };
let produtosMaisVendidos = {};
let vendasPorRegiao = {};
const hoje = new Date().toLocaleDateString('pt-BR');

for (const item of items) {
  const dados = item.json;

  // Adapte os nomes das colunas conforme seu CSV real
  const valor = parseFloat((dados['valor_venda'] || dados['Valor'] || 0).toString().replace(',', '.'));
  const vendedor = dados['vendedor'] || dados['Vendedor'] || 'N/A';
  const produto = dados['produto'] || dados['Produto'] || 'N/A';
  const regiao = dados['regiao'] || dados['Regi�o'] || dados['Regiao'] || 'N/A';

  totalVendas += valor;
  totalPedidos += 1;

  if (valor > melhorVendedor.valor) {
    melhorVendedor = { nome: vendedor, valor };
  }

  produtosMaisVendidos[produto] = (produtosMaisVendidos[produto] || 0) + valor;
  vendasPorRegiao[regiao] = (vendasPorRegiao[regiao] || 0) + valor;
}

// Top 3 produtos
const topProdutos = Object.entries(produtosMaisVendidos)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([nome, valor]) => ({ nome, valor: valor.toFixed(2) }));

// Top regi�es
const topRegioes = Object.entries(vendasPorRegiao)
  .sort((a, b) => b[1] - a[1])
  .map(([regiao, valor]) => ({ regiao, valor: valor.toFixed(2) }));

const metaDiaria = 50000; // Ajuste conforme a meta real
const percentualMeta = ((totalVendas / metaDiaria) * 100).toFixed(1);
const ticketMedio = totalPedidos > 0 ? (totalVendas / totalPedidos).toFixed(2) : 0;

return [{
  json: {
    data: hoje,
    totalVendas: totalVendas.toFixed(2),
    totalPedidos,
    ticketMedio,
    percentualMeta,
    melhorVendedor,
    topProdutos,
    topRegioes,
    metaDiaria,
    atingiuMeta: totalVendas >= metaDiaria
  }
}];

